import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';

// POST /api/attendance/stage1
// Endpoint for: Student scans QR -> App sends (temp_session_id, class_session_id)
export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { student_id, class_session_id, temp_session_id, verification_code_scanned } = body;

    // 1. Validate the temp_session_id is active and within time window
    const { data: qrSession, error: qrError } = await supabase
      .from('temp_qr_sessions')
      .select('expires_at, is_active')
      .eq('temp_session_id', temp_session_id)
      .eq('class_session_id', class_session_id)
      .single();

    if (qrError || !qrSession) {
      return NextResponse.json({ error: 'Invalid or missing QR session' }, { status: 400 });
    }

    if (!qrSession.is_active || new Date() > new Date(qrSession.expires_at)) {
      return NextResponse.json({ error: 'QR code has expired. Please scan the newest one.' }, { status: 410 });
    }

    // 2. Store the Scan Record (Stage 1 validation complete)
    const { data: logData, error: logError } = await supabase
      .from('attendance_logs')
      .insert({
        student_id,
        class_session_id,
        temp_session_id,
        scanned_at: new Date().toISOString(),
        stage_1_passed: true,
        final_status: 'PENDING'
      })
      .select()
      .single();

    if (logError) {
      return NextResponse.json({ error: 'Failed to store scan record' }, { status: 500 });
    }

    // 3. Return success to the App so it can unlock the Submit button
    return NextResponse.json({ 
      success: true, 
      message: 'Stage 1 Complete: QR Validated',
      scan_record_id: logData.id
    }, { status: 200 });

  } catch (err: any) {
    return NextResponse.json({ error: 'Internal server error', details: err.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';

// POST /api/attendance/stage2
// Endpoint for: Student taps submit -> App sends (temp_session_id, verification_code, device_fingerprint)
export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { 
      scan_record_id, 
      student_id, 
      temp_session_id, 
      verification_code_entered, 
      device_fingerprint,
      ble_detected 
    } = body;

    // 1. Double check BLE Requirement from the App
    if (!ble_detected) {
      return NextResponse.json({ error: 'BLE Beacon not detected. Must be in the classroom.' }, { status: 403 });
    }

    // 2. Fetch the student to verify Fingerprint matches Login Device
    const { data: student, error: studentError } = await supabase
      .from('students')
      .select('registered_device_fingerprint')
      .eq('id', student_id)
      .single();

    if (studentError || !student) {
      return NextResponse.json({ error: 'Student not found' }, { status: 404 });
    }

    if (student.registered_device_fingerprint !== device_fingerprint) {
      return NextResponse.json({ error: 'Unrecognized Device. Proxy attempt blocked.' }, { status: 403 });
    }

    // 3. Fetch the QR Session to verify the 6-digit visual code
    const { data: qrSession, error: qrError } = await supabase
      .from('temp_qr_sessions')
      .select('verification_code')
      .eq('temp_session_id', temp_session_id)
      .single();

    if (qrError || !qrSession) {
      return NextResponse.json({ error: 'Invalid Session.' }, { status: 400 });
    }

    if (qrSession.verification_code !== verification_code_entered) {
      return NextResponse.json({ error: 'Incorrect visual verification code.' }, { status: 401 });
    }

    // 4. Update the Scan Record (Stage 2 validation complete -> PRESENT)
    const { data: authData, error: authError } = await supabase
      .from('attendance_logs')
      .update({
        stage_2_passed: true,
        device_fingerprint_match: true,
        final_status: 'VERIFIED'
      })
      .eq('id', scan_record_id)
      .eq('student_id', student_id)
      .eq('final_status', 'PENDING') // Ensure it hasn't already been submitted
      .select()
      .single();

    if (authError || !authData) {
      return NextResponse.json({ error: 'Session already submitted or scan record invalid.' }, { status: 400 });
    }

    // 5. Success! Attendance is marked securely.
    return NextResponse.json({ 
      success: true, 
      message: 'Attendance successfully locked in.',
      record: authData
    }, { status: 200 });

  } catch (err: any) {
    return NextResponse.json({ error: 'Internal server error', details: err.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { device_id, roll_no, session_id, is_present } = body;

    // Validate incoming payload from ESP32
    if (!device_id || !roll_no || !session_id) {
      return NextResponse.json(
        { error: 'Missing required physical presence parameters' },
        { status: 400 }
      );
    }

    if (!is_present) {
      return NextResponse.json(
        { message: 'Presence not detected, ignoring update' },
        { status: 200 }
      );
    }

    // 1. Verify that the session is still active
    const { data: sessionData, error: sessionError } = await supabase
      .from('sessions')
      .select('status')
      .eq('session_id', session_id)
      .single();

    if (sessionError || !sessionData) {
        return NextResponse.json({ error: 'Session not found or invalid' }, { status: 404 });
    }

    if (sessionData.status !== 'ACTIVE') {
        return NextResponse.json({ error: 'Lab session is closed' }, { status: 403 });
    }

    // 2. Update the student's attendance to 'Present' in the database
    // This assumes they have already passed the Challenge-Response hash digitally via the app
    const { data, error } = await supabase
      .from('attendance')
      .update({ status: 'PRESENT', end_scan: new Date().toISOString() })
      .match({ roll_no: roll_no, session_id: session_id });

    if (error) {
      console.error("Supabase Error updating attendance:", error);
      return NextResponse.json({ error: 'Database update failed' }, { status: 500 });
    }

    return NextResponse.json({
      success: true,
      message: `Attendance marked PRESENT for student ${roll_no}`,
      device: device_id
    });

  } catch (error) {
    console.error("API Error processing ESP32 presence:", error);
    return NextResponse.json({ error: 'Internal Server Error processing payload' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';

// GET the current active lab session QR string for the ESP32 to display on OLED/E-Ink
export async function GET(request: Request) {
  try {
    const { data: session, error } = await supabase
      .from('sessions')
      .select('session_id, qr_data_string, expiry')
      .eq('status', 'ACTIVE')
      .order('created_at', { ascending: false })
      .limit(1)
      .single();

    if (error || !session) {
      return NextResponse.json(
        { error: 'No active lab session running' },
        { status: 404 }
      );
    }

    return NextResponse.json({
        success: true,
        session_id: session.session_id,
        qr_data_string: session.qr_data_string,
        expires_at: session.expiry
    });

  } catch (error) {
    console.error("API Error fetching active sesssion for ESP32:", error);
    return NextResponse.json({ error: 'Internal Server Error fetching active session' }, { status: 500 });
  }
}
